#include <stdio.h>
#include <stdlib.h>
int main() {
    int T, N, X, Y, i;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int rows = 0, cols = 0;
        int rowSet[N], colSet[N];
        for (i = 0; i < N; i++) {
            scanf("%d %d", &X, &Y);
            int foundRow = 0, foundCol = 0;
            for (int j = 0; j < rows; j++) {
                if (rowSet[j] == X) {
                    foundRow = 1;
                    break;
                }
            }
            for (int j = 0; j < cols; j++) {
                if (colSet[j] == Y) {
                    foundCol = 1;
                    break;
                }
            }
            if (!foundRow) {
                rowSet[rows] = X;
                rows++;
            }
            if (!foundCol) {
                colSet[cols] = Y;
                cols++;
            }
        }
        printf("%d\n", (rows < cols) ? rows : cols);
    }
    return 0;
}

