code.Java:
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] rowSet = new int[N];
            int[] colSet = new int[N];
            int rows = 0, cols = 0;
            for (int i = 0; i < N; i++) {
                int X = sc.nextInt();
                int Y = sc.nextInt();
                int foundRow = 0, foundCol = 0;
                for (int j = 0; j < rows; j++) {
                    if (rowSet[j] == X) {
                        foundRow = 1;
                        break;
                    }
                }
                for (int j = 0; j < cols; j++) {
                    if (colSet[j] == Y) {
                        foundCol = 1;
                        break;
                    }
                }
                if (!foundRow) {
                    rowSet[rows] = X;
                    rows++;
                }
                if (!foundCol) {
                    colSet[cols] = Y;
                    cols++;
                }
            }
            System.out.println(Math.min(rows, cols));
        }
    }
}

